import{_ as s,o as l,c as o,aj as e,ak as t}from"./chunks/framework.-P-BEnds.js";const u=JSON.parse('{"title":"Правила","description":"","frontmatter":{"title":"Правила","next":false},"headers":[],"relativePath":"codex/index.md","filePath":"codex/index.md"}'),p={name:"codex/index.md"};function n(c,a,r,i,d,m){return l(),o("div",null,[...a[0]||(a[0]=[e('<p><img src="'+t+'" alt="Изображение"></p><h1 id="правила-сервера" tabindex="-1">Правила сервера <a class="header-anchor" href="#правила-сервера" aria-label="Permalink to “Правила сервера”">​</a></h1><p><span style="color:#8C8C8C;">Правила поведения на Minecraft сервере.</span></p><div class="warning custom-block"><p class="custom-block-title"><span style="color:#eab308;">ПРИМЕЧАНИЕ</span></p><p>Методы наказания могут различаться в зависимости от тяжести нарушения и (или) на усмотрение модерации.</p></div><div class="danger custom-block"><p class="custom-block-title"><span style="color:#f43f5e;"><strong>ВНИМАНИЕ</strong></span></p><p>В случае бана на Minecraft-сервере, аналогичный бан будет применен на Discord-сервере, и наоборот.</p></div><h2 id="игра" tabindex="-1"><span style="color:#ff5555;">Игра</span> <a class="header-anchor" href="#игра" aria-label="Permalink to “Игра”">​</a></h2><p><span style="color:#ff5555;">1.</span> Запрещено использование утилит, читов, текстур-паков и модов, дающие преимущество перед другими игроками.</p><details class="details custom-block"><summary><span style="color:#ff5555;"><strong>ЗАПРЕЩЁННЫЙ ФУНКЦИОНАЛ</strong></span></summary><ul><li>Автоматизация действий игрока.</li><li>Обход стандартных ограничений скорости, высоты прыжка, голода и т.д.</li><li>Отсутствие урона от падения.</li><li>XRay и т.п.</li><li>KillAura, CristalAura и любой другой мод дающий сильное преимущество в PvP.</li><li>Автоматическая замена тотема и ломающихся предметов.</li><li>Работающий инвентарь во время ходьбы.</li><li>Freecam/свободный полет как в режиме наблюдателя.</li><li>Моды ускоряющие/упрощающие стройку/ломание блоков.</li><li>Отображение игроков/энтити сквозь блоки.</li><li>Отображение траектории полета стрел, эндер-перлов, снежков и т.п.</li><li>Мини-карта или любой другой способ видеть пространство под землей.</li><li>Позволяющий видеть невидимых игроков.</li><li>Обход эффекта «Тьма».<div class="danger custom-block"><p class="custom-block-title"><span style="color:#f43f5e;"><strong>ВНИМАНИЕ</strong></span></p><p>Хранение модов/текстур-паков с функционалом из этого списка – <strong>запрещено</strong>. Оправдание <em>&quot;Ыыы я же не использую&quot;</em> не аргумент.</p></div></li></ul></details><div class="info custom-block"><p class="custom-block-title"><span style="color:#657585;"><strong>ИСКЛЮЧЕНИЕ</strong></span></p><p><a href="https://modrinth.com/mod/legacyfreecam" target="_blank" rel="noreferrer">Freecam (Fair Play)</a>, <a href="https://modrinth.com/mod/litematica" target="_blank" rel="noreferrer">Litematica</a> с <strong>easyplacemode</strong></p></div><p><span style="color:#ff5555;">2.</span> Реклама сторонних Minecraft серверов.</p><p><span style="color:#ff5555;">3.</span> Обман/попытка ввести в заблуждение администрацию.</p><h2 id="коммуникация" tabindex="-1"><span style="color:#4da6ff;">Коммуникация</span> <a class="header-anchor" href="#коммуникация" aria-label="Permalink to “Коммуникация”">​</a></h2><p><span style="color:#4da6ff;">1.</span> Будьте взаимоуважительными! Помните, как Вы относитесь к игрокам, так и игроки к Вам. Травля, токсичное поведение, провокация и оскорбление игроков(а также их родных), в том числе по национальным и расовым признакам запрещена.</p><p><span style="color:#4da6ff;">2.</span> Запрещен бессмысленный или чрезмерный спам и флуд.</p><p><span style="color:#4da6ff;">3.</span> Запрещено провоцировать на острые темы, обсуждать политическую ситуацию в мире.</p><p><span style="color:#4da6ff;">4.</span> Запрещено демонстрировать по вебкамере 18+, NSFW, шокирующий или любой другой неприемлемый контент.</p><p><span style="color:#4da6ff;">5.</span> Намеренная попытка создания шума в голосовом чате для препятствия комуникации.</p><h2 id="имущество-и-территория" tabindex="-1"><span style="color:#55cc66;">Имущество и территория</span> <a class="header-anchor" href="#имущество-и-территория" aria-label="Permalink to “Имущество и территория”">​</a></h2><p><span style="color:#55cc66;">1.</span> Каждый игрок сервера имеет право на личное пространство и уважение к территории, где он строит или живет.</p><p><span style="color:#55cc66;">2.</span> Не разрушайте и не изменяйте чужие постройки без разрешения.</p><p><span style="color:#55cc66;">3.</span> Каждый игрок на своей территории может устанавливать свои правила, но правила сервера всегда будут выше.</p><div class="warning custom-block"><p class="custom-block-title"><span style="color:#eab308;"><strong>ПРИМЕЧАНИЕ</strong></span></p><p>Злоупотребление данным правом будет караться.</p><p><strong>Например:</strong> <em>&quot;Ты зашел на мою территорию, тебе штраф 128 алмазов&quot;</em></p></div><p><span style="color:#55cc66;">4.</span> Спавн является центральным поселением сервера и развивается по мере игры. Управление территорией спавна и порядок его развития определяются игроками, занимающимися его развитием.</p><div class="warning custom-block"><p class="custom-block-title"><span style="color:#eab308;"><strong>ПРИМЕЧАНИЕ</strong></span></p><p>Сервер не навязывает единую модель городского управления. Каждое поселение может самостоятельно устанавливать правила организации своей территории, если они не противоречат правилам сервера.</p></div><p><span style="color:#55cc66;">5.</span> Если игрок планирует занять территорию для строительства, рекомендуется заранее обозначить её любым понятным способом (например: табличкой, временной разметкой или началом стройки). В противном случае, необозначенная территория может считаться свободной для других игроков.</p><p><span style="color:#55cc66;">6.</span> Территориальные вопросы должны быть обоснованы реальным строительством или активным использованием зоны.</p><p><span style="color:#55cc66;">7.</span> Территория и постройки, которые не изменялись более 14 дней с момента создания или последней значимой модификации, могут быть признаны общественной территорией, если они:</p><ul><li><em>являются пустыми конструкциями (&quot;коробками&quot; без признаков проживания)</em></li><li><em>представляют собой разрушенные базы</em></li><li><em>не попадают под особые правила конкретного города или зоны</em></li></ul>',28)])])}const y=s(p,[["render",n]]);export{u as __pageData,y as default};
